// Determinism postcondition needs map extensional equality on the
// underlying *_perms@ maps and on cpu_list@.  The ensures only pin
// `get_X(p)` (which dereferences perms@[p].value()), so we re-assert
// each ensures-quantifier for both runs with EXPLICIT triggers, then
// transitively close the pointwise equalities, then lift to map
// extensional equality.  Every assertion is something Verus must
// verify — no assume/admit.

let queue0 = pre_self_.get_endpoint(endpoint_ptr).queue@[0];
let cont0 = pre_self_.get_thread(queue0).owning_container;

// ----------------------------------------------------------------
// 1. Domain equalities (dom of each *_perms@ matches across runs).
// ----------------------------------------------------------------
assert(post1_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post2_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post1_self_.container_dom() == pre_self_.container_dom());
assert(post2_self_.container_dom() == pre_self_.container_dom());
assert(post1_self_.thread_dom() == pre_self_.thread_dom());
assert(post2_self_.thread_dom() == pre_self_.thread_dom());
assert(post1_self_.endpoint_dom() == pre_self_.endpoint_dom());
assert(post2_self_.endpoint_dom() == pre_self_.endpoint_dom());

assert(post1_self_.process_perms@.dom() =~= post2_self_.process_perms@.dom());
assert(post1_self_.container_perms@.dom() =~= post2_self_.container_perms@.dom());
assert(post1_self_.thread_perms@.dom() =~= post2_self_.thread_perms@.dom());
assert(post1_self_.endpoint_perms@.dom() =~= post2_self_.endpoint_perms@.dom());

// page_closure preserved across both runs (transitively equal).
assert(post1_self_.page_closure() =~= pre_self_.page_closure());
assert(post2_self_.page_closure() =~= pre_self_.page_closure());

// ----------------------------------------------------------------
// 2. Pointwise process equality across both runs.
//    Force triggers `post1_self_.get_proc(p_ptr)` and
//    `post2_self_.get_proc(p_ptr)` to line up.
// ----------------------------------------------------------------
assert forall|p_ptr: ProcPtr|
    #![trigger post1_self_.get_proc(p_ptr), post2_self_.get_proc(p_ptr)]
    pre_self_.proc_dom().contains(p_ptr) implies
    post1_self_.get_proc(p_ptr) =~= post2_self_.get_proc(p_ptr) by {
    assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
    assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
}

// ----------------------------------------------------------------
// 3. Pointwise container equality across both runs.
// ----------------------------------------------------------------
assert forall|c_ptr: ContainerPtr|
    #![trigger post1_self_.get_container(c_ptr), post2_self_.get_container(c_ptr)]
    pre_self_.container_dom().contains(c_ptr) implies
    post1_self_.get_container(c_ptr) =~= post2_self_.get_container(c_ptr) by {
    assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
    assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
}

// ----------------------------------------------------------------
// 4. Pointwise thread equality for t_ptr != queue0 (the one
//    modified thread).  Ensures uses #![trigger old.get_thread(t)] —
//    we explicitly trigger on `pre_self_.get_thread(t_ptr)`.
// ----------------------------------------------------------------
assert forall|t_ptr: ThreadPtr|
    #![trigger pre_self_.get_thread(t_ptr)]
    pre_self_.thread_dom().contains(t_ptr) && t_ptr != queue0 implies
    post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {
    assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
    assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
}

// ----------------------------------------------------------------
// 5. Pointwise endpoint equality for e_ptr != endpoint_ptr.
// ----------------------------------------------------------------
assert forall|e_ptr: EndpointPtr|
    #![trigger post1_self_.get_endpoint(e_ptr), post2_self_.get_endpoint(e_ptr)]
    pre_self_.endpoint_dom().contains(e_ptr) && e_ptr != endpoint_ptr implies
    post1_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr) by {
    assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
    assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
}

// ----------------------------------------------------------------
// 6. Endpoint at endpoint_ptr (the only modified endpoint): each
//    field forced equal across runs through pre_self_.
// ----------------------------------------------------------------
assert(post1_self_.get_endpoint(endpoint_ptr).queue@
    =~= pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1));
assert(post2_self_.get_endpoint(endpoint_ptr).queue@
    =~= pre_self_.get_endpoint(endpoint_ptr).queue@.skip(1));
assert(post1_self_.get_endpoint(endpoint_ptr).queue@
    =~= post2_self_.get_endpoint(endpoint_ptr).queue@);
assert(post1_self_.get_endpoint(endpoint_ptr).owning_threads
    == pre_self_.get_endpoint(endpoint_ptr).owning_threads);
assert(post2_self_.get_endpoint(endpoint_ptr).owning_threads
    == pre_self_.get_endpoint(endpoint_ptr).owning_threads);
assert(post1_self_.get_endpoint(endpoint_ptr).rf_counter
    == pre_self_.get_endpoint(endpoint_ptr).rf_counter);
assert(post2_self_.get_endpoint(endpoint_ptr).rf_counter
    == pre_self_.get_endpoint(endpoint_ptr).rf_counter);
assert(post1_self_.get_endpoint(endpoint_ptr).queue_state
    == pre_self_.get_endpoint(endpoint_ptr).queue_state);
assert(post2_self_.get_endpoint(endpoint_ptr).queue_state
    == pre_self_.get_endpoint(endpoint_ptr).queue_state);

// ----------------------------------------------------------------
// 7. Thread at queue0 (the dequeued thread).
// ----------------------------------------------------------------
assert(post1_self_.get_thread(queue0).endpoint_descriptors
    =~= pre_self_.get_thread(queue0).endpoint_descriptors);
assert(post2_self_.get_thread(queue0).endpoint_descriptors
    =~= pre_self_.get_thread(queue0).endpoint_descriptors);
assert(post1_self_.get_thread(queue0).state == ThreadState::RUNNING);
assert(post2_self_.get_thread(queue0).state == ThreadState::RUNNING);

// ----------------------------------------------------------------
// 8. Container at cont0 (the owning container).
// ----------------------------------------------------------------
assert(post1_self_.get_container(cont0).owned_procs
    =~= pre_self_.get_container(cont0).owned_procs);
assert(post2_self_.get_container(cont0).owned_procs
    =~= pre_self_.get_container(cont0).owned_procs);

// ----------------------------------------------------------------
// 9. CPU at cpu_id: current_thread is Some(queue0) on both runs.
// ----------------------------------------------------------------
assert(post1_self_.get_cpu(cpu_id).current_thread.is_Some());
assert(post2_self_.get_cpu(cpu_id).current_thread.is_Some());
assert(post1_self_.get_cpu(cpu_id).current_thread.unwrap() == queue0);
assert(post2_self_.get_cpu(cpu_id).current_thread.unwrap() == queue0);

// ----------------------------------------------------------------
// 10. wf() for both posts (needed to derive .is_init() / .addr()
//     equalities on the underlying PointsTo values).
// ----------------------------------------------------------------
assert(post1_self_.wf());
assert(post2_self_.wf());
